cast call $OPERATOR_ADDRESS "getMessagingModule()" --rpc-url $OPTIMISM_TESTNET_SEPOLIA_RPC_URL
cast call $LZ_MODULE_V2 "getLZEndpoint()" --rpc-url $OPTIMISM_TESTNET_SEPOLIA_RPC_URL 
cast call $LZ_MODULE_V2 "admin()" --rpc-url $OPTIMISM_TESTNET_SEPOLIA_RPC_URL 


cast send 0x2Dd7Cf028201e68Af8A44ACBe0437dc54d0DBd7f "setPeer(uint32,bytes32)" 40231 0x000000000000000000000000071eE3E82af00aA493367b62403EEFb17254DCc8 --rpc-url $OPTIMISM_TESTNET_SEPOLIA_RPC_URL --private-key $DEPLOYER
cast send 0x071eE3E82af00aA493367b62403EEFb17254DCc8 "setPeer(uint32,bytes32)" 40232 0x0000000000000000000000002Dd7Cf028201e68Af8A44ACBe0437dc54d0DBd7f --rpc-url $ARBITRUM_TESTNET_SEPOLIA_RPC_URL --private-key $DEPLOYER

cast call 0x2Dd7Cf028201e68Af8A44ACBe0437dc54d0DBd7f "peers(uint32)" 40231 --rpc-url $OPTIMISM_TESTNET_SEPOLIA_RPC_URL
cast call 0x071eE3E82af00aA493367b62403EEFb17254DCc8 "peers(uint32)" 40232 --rpc-url $ARBITRUM_TESTNET_SEPOLIA_RPC_URL



cast send 0x9f411c719DCBD22716ff1B78f0dDFbd8C214f11B "executeJob(bytes)"  --rpc-url $ARBITRUM_TESTNET_SEPOLIA_RPC_URL --private-key $DEPLOYER

